	import org.springframework.boot.context.properties.bind.BindResult;
	import org.springframework.boot.context.properties.bind.Bindable;
	import org.springframework.boot.context.properties.bind.Binder;
	import org.springframework.boot.context.properties.source.MapConfigurationPropertySource;

	public class PropertiesTest {

		@Test
		void bindsPathProperty() {
			String expectedPathValue = "some_value";
			Map<String, String> properties = new HashMap<>();
			properties.put("some_path_property", expectedPathValue);
			Binder binder = new Binder(new MapConfigurationPropertySource(properties));

			BindResult<ConfigurationPropertiesWithPathProperty> bindResult =
					binder.bind("", Bindable.of(ConfigurationPropertiesWithPathProperty.class));

			assertThat(bindResult.get().getSomePathProperty())
					.isEqualTo(Paths.get(expectedPathValue));
		}
	}

